app.post('/authorize/consent', (req, res) => {
  const { client_id, redirect_uri, scope, state, username, password, consent } = req.body;

  if (consent !== 'approve') {
    const params = querystring.stringify({
      error: 'access_denied',
      error_description: 'User denied the request',
      state: state || ''
    });
    return res.redirect(`${redirect_uri}?${params}`);
  }

  const user = users[username];
  if (!user || user.password !== password) {
    return res.status(401).send('Invalid username or password');
  }

  const authCode = generateRandomString();
  authorizationCodes.set(authCode, {
    client_id,
    redirect_uri,
    scope: scope || '',
    user_id: user.user_id,
    expires_at: Date.now() + 600000,
    used: false
  });

  const params = querystring.stringify({
    code: authCode,
    state: state || ''
  });

  res.redirect(`${redirect_uri}?${params}`);
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  let authClientId = client_id;
  let authClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const credentials = Buffer.from(authHeader.substring(6), 'base64').toString('utf-8');
    const [id, secret] = credentials.split(':');
    authClientId = id;
    authClientSecret = secret;
  }

  if (!grant_type || grant_type !== 'authorization_code') {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Only authorization_code grant type is supported'
    });
  }

  if (!code) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Authorization code is required'
    });
  }

  if (!authClientId || !authClientSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed'
    });
  }

  const client = clients[authClientId];
  if (!client || client.client_secret !== authClientSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed'
    });
  }

  const authData = authorizationCodes.get(code);
  if (!authData) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid authorization code'
    });
  }

  if (authData.used) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has already been used'
    });
  }

  if (authData.expires_at < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has expired'
    });
  }

  if (authData.client_id !== authClientId) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was issued to another client'
    });
  }

  if (authData.redirect_uri !== redirect_uri) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'redirect_uri does not match'
    });
  }

  authData.used = true;

  const accessToken = generateRandomString();
  const refreshToken = generateRandomString();

  accessTokens.set(accessToken, {
    client_id: authClientId,
    user_id: authData.user_id,
    scope: authData.scope,
    expires_at: Date.now() + 3600000
  });

  accessTokens.set(refreshToken, {
    client_id: authClientId,
    user_id: authData.user_id,
    scope: authData.scope,
    type: 'refresh',
    expires_at: Date.now() + 86400000
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: refreshToken,
    scope: authData.scope
  });
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Missing or invalid authorization header'
    });
  }

  const accessToken = authHeader.substring(7);
  const tokenData = accessTokens.get(accessToken);

  if (!tokenData || tokenData.type === 'refresh') {
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Invalid access token'
    });
  }

  if (tokenData.expires_at < Date.now()) {
    accessTokens.delete(accessToken);
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Access token has expired'
    });
  }

  res.json({
    sub: tokenData.user_id,
    user_id: tokenData.user_id,
    scope: tokenData.scope
  });
});

